CREATE EXTENSION IF NOT EXISTS pgcrypto;
CREATE TYPE user_role AS ENUM ('supporter', 'ngo', 'corporate', 'admin');
CREATE TYPE campaign_status AS ENUM ('draft', 'pending_review', 'changes_requested', 'rejected', 'approved', 'active', 'paused', 'completed', 'cancelled');
CREATE TYPE verification_status AS ENUM ('draft', 'submitted', 'changes_requested', 'verified', 'rejected', 'expired');

CREATE TABLE users (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), name TEXT NOT NULL, email TEXT NOT NULL UNIQUE, email_verified BOOLEAN NOT NULL DEFAULT false, image TEXT, role user_role NOT NULL DEFAULT 'supporter', created_at TIMESTAMPTZ NOT NULL DEFAULT now(), updated_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE sessions (id TEXT PRIMARY KEY, user_id UUID NOT NULL REFERENCES users(id) ON DELETE CASCADE, token TEXT NOT NULL UNIQUE, expires_at TIMESTAMPTZ NOT NULL, ip_address TEXT, user_agent TEXT, created_at TIMESTAMPTZ NOT NULL DEFAULT now(), updated_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE INDEX sessions_user_idx ON sessions(user_id);
CREATE TABLE accounts (id TEXT PRIMARY KEY, user_id UUID NOT NULL REFERENCES users(id) ON DELETE CASCADE, account_id TEXT NOT NULL, provider_id TEXT NOT NULL, password TEXT, access_token TEXT, refresh_token TEXT, access_token_expires_at TIMESTAMPTZ, refresh_token_expires_at TIMESTAMPTZ, scope TEXT, id_token TEXT, created_at TIMESTAMPTZ NOT NULL DEFAULT now(), updated_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE verifications (id TEXT PRIMARY KEY, identifier TEXT NOT NULL, value TEXT NOT NULL, expires_at TIMESTAMPTZ NOT NULL, created_at TIMESTAMPTZ NOT NULL DEFAULT now(), updated_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE ngo_profiles (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), owner_id UUID NOT NULL REFERENCES users(id), display_name TEXT NOT NULL, slug TEXT NOT NULL UNIQUE, description TEXT, city TEXT, state TEXT, categories TEXT[] NOT NULL DEFAULT '{}', verification_status verification_status NOT NULL DEFAULT 'draft', is_discoverable BOOLEAN NOT NULL DEFAULT false, is_80g_eligible BOOLEAN NOT NULL DEFAULT false, created_at TIMESTAMPTZ NOT NULL DEFAULT now(), updated_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE payout_accounts (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), owner_id UUID NOT NULL REFERENCES users(id), provider TEXT NOT NULL, gateway_account_id TEXT, status TEXT NOT NULL DEFAULT 'pending', beneficiary JSONB, created_at TIMESTAMPTZ NOT NULL DEFAULT now(), updated_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE campaigns (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), creator_id UUID NOT NULL REFERENCES users(id), ngo_id UUID REFERENCES ngo_profiles(id), payout_account_id UUID REFERENCES payout_accounts(id), title TEXT NOT NULL, story TEXT NOT NULL, target_paise BIGINT NOT NULL CHECK (target_paise > 0), status campaign_status NOT NULL DEFAULT 'draft', created_at TIMESTAMPTZ NOT NULL DEFAULT now(), updated_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE INDEX campaigns_status_idx ON campaigns(status);
CREATE TABLE donations (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), donor_id UUID NOT NULL REFERENCES users(id), campaign_id UUID NOT NULL REFERENCES campaigns(id), amount_paise BIGINT NOT NULL CHECK (amount_paise > 0), gateway_order_id TEXT NOT NULL UNIQUE, gateway_payment_id TEXT NOT NULL UNIQUE, status TEXT NOT NULL, captured_at TIMESTAMPTZ NOT NULL, created_at TIMESTAMPTZ NOT NULL DEFAULT now(), updated_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE payment_events (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), gateway_event_id TEXT NOT NULL UNIQUE, event_type TEXT NOT NULL, payload JSONB NOT NULL, processed_at TIMESTAMPTZ, created_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE volunteer_applications (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), user_id UUID NOT NULL REFERENCES users(id), ngo_id UUID NOT NULL REFERENCES ngo_profiles(id), status TEXT NOT NULL DEFAULT 'submitted', created_at TIMESTAMPTZ NOT NULL DEFAULT now(), updated_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE posts (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), author_id UUID NOT NULL REFERENCES users(id), body TEXT NOT NULL, approved_at TIMESTAMPTZ, hidden_at TIMESTAMPTZ, created_at TIMESTAMPTZ NOT NULL DEFAULT now(), updated_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE audit_logs (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), actor_id UUID REFERENCES users(id), action TEXT NOT NULL, entity_type TEXT NOT NULL, entity_id TEXT, metadata JSONB, created_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE reviews (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), user_id UUID NOT NULL REFERENCES users(id), ngo_id UUID NOT NULL REFERENCES ngo_profiles(id), rating INTEGER NOT NULL CHECK (rating BETWEEN 1 AND 5), body TEXT, hidden_at TIMESTAMPTZ, created_at TIMESTAMPTZ NOT NULL DEFAULT now(), UNIQUE (user_id, ngo_id));
